const e=JSON.parse('{"key":"v-44d8e598","path":"/learningNote/vueNote/VUE3/VUE3_Vs_VUE2_In_Render_Function.html","title":"Vue3 与 Vue2 在渲染函数上的区别","lang":"zh-CN","frontmatter":{"category":["VUE","Web"],"tag":["VUE3","COMPARE"]},"headers":[],"git":{"createdTime":1692704943000,"updatedTime":1692704943000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":1}]},"readingTime":{"minutes":1.93,"words":579},"filePathRelative":"learningNote/vueNote/VUE3/VUE3_Vs_VUE2_In_Render_Function.md","localizedDate":"2023年8月22日","excerpt":"<h1> Vue3 与 Vue2 在渲染函数上的区别</h1>\\n<p>在编写vue代码时，我们一般会首先在template标签中编写html代码。当我们进行代码编译时，VUE首先会<u>根据代码内的各个标签将代码转换为若干个虚拟DOM节点</u>，也就是VNode (VirtualDomNode)，然后它会将多个 Vnode 结合，将其转化为VirtalDOM，最后VDOM才会被渲染成真实的DOM。大部分的情况都会是如此。</p>\\n<p>但是如果我们可以跳过代码转换节点的过程，直接编写生成vnode的代码，会使得浏览器编译代码的效率更高。此时我们可以在script标签内使用渲染函数render(), 并在其中调用VUE中的函数h()。h函数中调用了createElement函数（Vue3中使用的是createVnode函数） 进行结点的创建，但是只是在这之上进行了传入参数的条件判断，所以我们也可以称其为createElement函数/createVnode函数。</p>"}');export{e as data};
